  padding-bottom: 1.4px;
  padding-inline-end: 3.5px;
  padding-inline-start: 3.5px;
  padding-left: 3.5px;
  padding-right: 3.5px;
  padding-top: 1.4px;
}

html[saved-theme="light"] body li.task-list-item input[type="checkbox"] {
  background-color: rgba(0, 0, 0, 0);
  border-color: rgb(129, 129, 132);
  border-radius: 4px;
  border-width: 1px;
}

html[saved-theme="light"] body li.task-list-item input[type="checkbox"]:checked {
  background-color: var(--checkbox-color);
  border-color: rgba(0, 0, 0, 0);
}

html[saved-theme="light"] body pre:has(> code.mermaid) {
  background-color: var(--code-background);
  border: 0px solid rgb(129, 129, 132);
}

html[saved-theme="light"] body progress {
  background-color: rgba(0, 0, 0, 0);
  border-bottom-color: rgb(8, 9, 14);
  border-bottom-left-radius: 0px;
  border-bottom-right-radius: 0px;
  border-bottom-width: 0px;
  border-left-color: rgb(8, 9, 14);
  border-left-width: 0px;
  border-right-color: rgb(8, 9, 14);
  border-right-width: 0px;
  border-top-color: rgb(8, 9, 14);
  border-top-left-radius: 0px;
  border-top-right-radius: 0px;
  border-top-width: 0px;
  height: 6px;
}

html[saved-theme="light"] body sub {
  color: var(--text-normal);
  font-size: var(--font-text-size);
  vertical-align: sub;
}

html[saved-theme="light"] body summary {
  background-color: rgba(0, 0, 0, 0);
  color: var(--text-normal);
  font-weight: 400;
  list-style: inside none disclosure-closed;
  padding-block-end: 0px;
  padding-block-start: 0px;
  padding-bottom: 0px;
  padding-inline-end: 0px;
  padding-inline-start: 0px;
  padding-left: 0px;
  padding-right: 0px;
  padding-top: 0px;
}

html[saved-theme="light"] body sup {
  color: var(--text-normal);
  font-size: var(--font-text-size);
  vertical-align: super;
}

html[saved-theme="light"] body ul.tags > li {
  --icon-size: var(--icon-xs);
  --icon-stroke: var(--icon-xs-stroke-width);
